  ('immigration-1aab856d-moex-00120', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '關於行政裁量之敘述，下列何者錯誤？', '["行政機關之裁量，應遵守行政法上一般原理原則", "行政機關原則上應依裁量基準行使裁量權", "裁量處分不得附加附款", "超過法定罰鍰數額之處罰，為裁量逾越"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "7185f513df9b", "answer_pdf_sha1": "13755252dfea", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00121', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '某直轄市政府為管理街頭藝人，自行訂定該直轄市之街頭藝人從事藝文活動許可辦法，規定 街頭藝人從事街頭表演前，須先申請許可。依司法院大法官解釋意旨，下列敘述何者正確？', '["從事街頭表演應先申請許可，得以自治規則定之", "街頭藝人之管理屬地方自治事項，得免除法律保留原則之適用", "以自治規則作為限制街頭表演之依據，應有自治條例之明確授權", "自治規則應由地方立法機關自行制定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "7185f513df9b", "answer_pdf_sha1": "13755252dfea", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00122', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '依中央行政機關組織基準法規定，下列何機關之組織得以命令定之？', '["國家發展委員會", "內政部警政署刑事警察局", "國家通訊傳播委員會", "法務部行政執行署"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "7185f513df9b", "answer_pdf_sha1": "13755252dfea", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00123', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '關於行政機關管轄之敘述，下列何者錯誤？', '["依地域範圍定行政機關之事務管轄者，稱為土地管轄", "土地管轄之範圍可同時跨越不同之行政區域", "數行政機關皆有管轄權時，由各該機關共同管轄", "管轄權不得由機關任意創設及變更"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "7185f513df9b", "answer_pdf_sha1": "13755252dfea", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00124', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '依最高行政法院裁判見解及行政程序法之規定，關於公法上不當得利之敘述，下列何者錯誤？', '["公法上不當得利之類型不限於給付型不當得利，亦包括非給付型不當得利", "國家行使公權力利用人民之物，致人民失其對該物之使用權能，為權利侵害型之公法上不 當得利", "以提供金錢給付為內容之授益行政處分經廢止後，不論是否有溯及既往失效之情形，受益 人均應返還所受領之金錢給付", "須公法上一方受利益而他方受損害，受利益與受損害間有直接因果關係，且受利益係無法 律上原因，始成立公法上不當得利"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "7185f513df9b", "answer_pdf_sha1": "13755252dfea", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00125', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '下列何者並非公務人員任用法所定義之公務員？', '["苗栗縣政府之官職等為薦任六等之社會工作師", "臺北市政府觀光傳播局聘用研究員", "高雄市政府以機要人員方式進用之市政府副秘書長", "花蓮縣警察局官等為警監之局長"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "7185f513df9b", "answer_pdf_sha1": "13755252dfea", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00126', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '依司法院大法官解釋意旨，有關公務員與國家法律關係之敘述，下列何者錯誤？', '["法律保留原則適用於公務員法律關係，惟為維繫公務推展的靈活性及公務員制度之功能， 得運用不確定法律概念或概括條款", "公務員法律關係中之管理措施，如可能影響該公務員之權利者，公務員得提起權利救濟", "行政機關對公務員所作成之考績處分，行政法院應予以適度之尊重", "公務員法律關係與國家之於人民的權力關係完全等同，因此任何職務上之指示皆應給予公 務員權利救濟管道"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "7185f513df9b", "answer_pdf_sha1": "13755252dfea", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00127', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '關於法規命令訂定之敘述，下列何者正確？', '["法規命令未經預告程序即發布者，尚未生效", "行政機關訂定法規命令，應舉行聽證程序", "人民提議訂定法規命令被拒絕，得提起訴願", "法規命令僅在網路發布，尚未生效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "7185f513df9b", "answer_pdf_sha1": "13755252dfea", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00128', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '下列機關所訂定之行政命令，何者非屬行政規則？', '["地方法院所訂定之內部事務分配規定", "縣政府所訂定公務員服裝儀容之規定", "交通部訂頒之違反道路交通管理事件統一裁罰標準表", "內政部依法律所訂定之施行細則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "7185f513df9b", "answer_pdf_sha1": "13755252dfea", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00129', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '行政處分於法定救濟期間經過後，相對人或利害關係人之申請程序重開，下列敘述何者正確？', '["應自法定救濟期間經過後2個月內申請重開", "發生新事實或發現新證據，如經斟酌可受較有利益之處分者，得申請重開", "其他適用訴願法所定再審事由且足以影響行政處分者，得申請重開", "自法定救濟期間經過後已逾3年者，不得申請重開"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "7185f513df9b", "answer_pdf_sha1": "13755252dfea", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL)
